--- src/store/optimisticStore.ts L57
+  applyServerUpdate(postId: string, count: number, serverVersion: number): PostLikeState {
+    const current = this.get(postId);
+    // If the current state is optimistic, any server-confirmed update should take precedence.
+    // Otherwise, only apply the server update if its version is newer or equal to the current confirmed version.
+    if (current.optimistic) {
+      const next: PostLikeState = { postId, count, version: serverVersion, optimistic: false };
+      this.state.set(postId, next);
+      return next;
+    } else if (serverVersion >= current.version) {
+      const next: PostLikeState = { postId, count, version: serverVersion, optimistic: false };
+      this.state.set(postId, next);
+      return next;
+    }
+    // Ignore stale server updates if a newer confirmed state already exists.
+    return current;
+  }
